import { useState, useCallback, useRef } from 'react'
import { Project } from '../../../stores/workspace.js'
import { DropTarget } from '../types.js'

interface UseDragAndDropOptions {
  projects: Project[]
  moveProjectToCategory: (projectPath: string, categoryId: string | null) => void
  reorderProjects: (categoryId: string | null, projectPaths: string[]) => void
  reorderCategories: (categoryIds: string[]) => void
  categories: Array<{ id: string; name: string; order: number; collapsed?: boolean }>
}

interface UseDragAndDropReturn {
  draggedProject: string | null
  draggedCategory: string | null
  dropTarget: DropTarget | null
  handleProjectDragStart: (e: React.DragEvent, projectPath: string) => void
  handleProjectDragEnd: () => void
  handleCategoryDragOver: (e: React.DragEvent, categoryId: string | null) => void
  handleCategoryDrop: (e: React.DragEvent, categoryId: string | null) => void
  handleProjectDragOver: (
    e: React.DragEvent,
    projectPath: string,
    position: 'before' | 'after'
  ) => void
  handleProjectDrop: (
    e: React.DragEvent,
    targetPath: string,
    targetCategoryId: string | undefined
  ) => void
  handleCategoryDragStart: (e: React.DragEvent, categoryId: string) => void
  handleCategoryDragEnd: () => void
  handleCategoryHeaderDragOver: (
    e: React.DragEvent,
    targetCategoryId: string,
    position: 'before' | 'after'
  ) => void
  handleCategoryHeaderDrop: (e: React.DragEvent, targetCategoryId: string) => void
}

export function useDragAndDrop({
  projects,
  moveProjectToCategory,
  reorderProjects,
  reorderCategories,
  categories,
}: UseDragAndDropOptions): UseDragAndDropReturn {
  const [draggedProject, setDraggedProject] = useState<string | null>(null)
  const [draggedCategory, setDraggedCategory] = useState<string | null>(null)
  const [dropTarget, setDropTarget] = useState<DropTarget | null>(null)
  // Ref tracks the latest dropTarget so drop handlers always read fresh position
  // (state in the closure may be stale if React hasn't re-rendered since the last dragOver)
  const dropTargetRef = useRef<DropTarget | null>(null)

  const handleProjectDragStart = useCallback((e: React.DragEvent, projectPath: string) => {
    setDraggedProject(projectPath)
    e.dataTransfer.effectAllowed = 'move'
    e.dataTransfer.setData('text/plain', projectPath)
    // Also set custom type so TiledTerminalView can detect sidebar project drags
    e.dataTransfer.setData('application/x-sidebar-project', projectPath)
  }, [])

  const handleProjectDragEnd = useCallback(() => {
    setDraggedProject(null)
    setDropTarget(null)
    dropTargetRef.current = null
  }, [])

  const handleCategoryDragOver = useCallback(
    (e: React.DragEvent, categoryId: string | null) => {
      e.preventDefault()
      e.dataTransfer.dropEffect = 'move'
      if (draggedProject) {
        const target: DropTarget = {
          type: categoryId ? 'category' : 'uncategorized',
          id: categoryId,
        }
        setDropTarget(target)
        dropTargetRef.current = target
      }
    },
    [draggedProject]
  )

  const handleCategoryDrop = useCallback(
    (e: React.DragEvent, categoryId: string | null) => {
      e.preventDefault()
      if (draggedProject) {
        moveProjectToCategory(draggedProject, categoryId)
      }
      setDraggedProject(null)
      setDropTarget(null)
      dropTargetRef.current = null
    },
    [draggedProject, moveProjectToCategory]
  )

  const handleProjectDragOver = useCallback(
    (e: React.DragEvent, projectPath: string, position: 'before' | 'after') => {
      e.preventDefault()
      e.stopPropagation()
      e.dataTransfer.dropEffect = 'move'
      if (draggedProject && draggedProject !== projectPath) {
        const target: DropTarget = { type: 'project', id: projectPath, position }
        setDropTarget(target)
        dropTargetRef.current = target
      }
    },
    [draggedProject]
  )

  const handleProjectDrop = useCallback(
    (e: React.DragEvent, targetPath: string, targetCategoryId: string | undefined) => {
      e.preventDefault()
      e.stopPropagation()

      if (draggedProject && draggedProject !== targetPath) {
        const draggedProjectData = projects.find((p) => p.path === draggedProject)
        const targetProject = projects.find((p) => p.path === targetPath)

        if (draggedProjectData && targetProject) {
          moveProjectToCategory(draggedProject, targetCategoryId ?? null)
          const categoryProjects = projects
            .filter((p) =>
              targetCategoryId ? p.categoryId === targetCategoryId : !p.categoryId
            )
            .sort((a, b) => (a.order ?? 0) - (b.order ?? 0))
            .map((p) => p.path)

          const newOrder = categoryProjects.filter((p) => p !== draggedProject)
          const targetIndex = newOrder.indexOf(targetPath)
          // Read from ref to get the latest position (state may be stale)
          const currentDropTarget = dropTargetRef.current
          const insertIndex = currentDropTarget?.position === 'after' ? targetIndex + 1 : targetIndex
          newOrder.splice(insertIndex, 0, draggedProject)
          reorderProjects(targetCategoryId ?? null, newOrder)
        }
      }
      setDraggedProject(null)
      setDropTarget(null)
      dropTargetRef.current = null
    },
    [draggedProject, projects, moveProjectToCategory, reorderProjects]
  )

  const handleCategoryDragStart = useCallback((e: React.DragEvent, categoryId: string) => {
    setDraggedCategory(categoryId)
    e.dataTransfer.effectAllowed = 'move'
    e.dataTransfer.setData('text/plain', categoryId)
  }, [])

  const handleCategoryDragEnd = useCallback(() => {
    setDraggedCategory(null)
    setDropTarget(null)
    dropTargetRef.current = null
  }, [])

  const handleCategoryHeaderDragOver = useCallback(
    (e: React.DragEvent, targetCategoryId: string, position: 'before' | 'after') => {
      e.preventDefault()
      e.dataTransfer.dropEffect = 'move'
      if (draggedCategory && draggedCategory !== targetCategoryId) {
        const target: DropTarget = { type: 'category', id: targetCategoryId, position }
        setDropTarget(target)
        dropTargetRef.current = target
      }
    },
    [draggedCategory]
  )

  const handleCategoryHeaderDrop = useCallback(
    (e: React.DragEvent, targetCategoryId: string) => {
      e.preventDefault()
      if (draggedCategory && draggedCategory !== targetCategoryId) {
        const orderedCategories = [...categories].sort((a, b) => a.order - b.order)
        const categoryIds = orderedCategories.map((c) => c.id)
        const newOrder = categoryIds.filter((id) => id !== draggedCategory)
        const targetIndex = newOrder.indexOf(targetCategoryId)
        // Read from ref to get the latest position (state may be stale)
        const currentDropTarget = dropTargetRef.current
        const insertIndex = currentDropTarget?.position === 'after' ? targetIndex + 1 : targetIndex
        newOrder.splice(insertIndex, 0, draggedCategory)
        reorderCategories(newOrder)
      }
      setDraggedCategory(null)
      setDropTarget(null)
      dropTargetRef.current = null
    },
    [draggedCategory, categories, reorderCategories]
  )

  return {
    draggedProject,
    draggedCategory,
    dropTarget,
    handleProjectDragStart,
    handleProjectDragEnd,
    handleCategoryDragOver,
    handleCategoryDrop,
    handleProjectDragOver,
    handleProjectDrop,
    handleCategoryDragStart,
    handleCategoryDragEnd,
    handleCategoryHeaderDragOver,
    handleCategoryHeaderDrop,
  }
}

import { useCallback, useRef } from 'react'
import { Project, useWorkspaceStore } from '../../stores/workspace.js'
import { SidebarState } from './useSidebarState.js'
import { SidebarProps } from './types.js'

// Use type assertion for extended electronAPI methods not in the base type
const electronAPI = window.electronAPI as (typeof window.electronAPI) & {
  selectExecutable?: () => Promise<string | null>
  runExecutable?: (executable: string, cwd: string) => Promise<{ success: boolean; error?: string }>
  getCategoryMetaPath?: (categoryName: string) => Promise<string>
  getMetaProjectsPath?: () => Promise<string>
}

export interface SidebarHandlers {
  // Project handlers
  handleSelectExecutable: (project: Project) => Promise<void>
  handleClearExecutable: (project: Project) => void
  handleRunExecutable: (project: Project) => Promise<void>

  // Rename handlers
  handleStartRename: (e: React.MouseEvent, project: Project) => void
  handleRenameSubmit: () => void
  handleRenameKeyDown: (e: React.KeyboardEvent) => void

  // Category handlers
  handleAddCategory: () => void
  handleOpenCategoryAsProject: (categoryName: string) => Promise<void>
  handleOpenAllProjects: () => Promise<void>
  handleStartCategoryRename: (
    category: ReturnType<typeof useWorkspaceStore.getState>['categories'][0]
  ) => void
  handleCategoryRenameSubmit: () => void
  handleCategoryRenameKeyDown: (e: React.KeyboardEvent) => void
  toggleCategoryCollapse: (categoryId: string) => void

  // Resize handler
  handleMouseDown: (e: React.MouseEvent) => void

  // Backdrop handler
  handleBackdropClick: () => void
}

export interface UseSidebarHandlersParams {
  state: SidebarState
  onUpdateProject: SidebarProps['onUpdateProject']
  onOpenSession: SidebarProps['onOpenSession']
  isMobile: boolean
  onMobileClose: (() => void) | undefined
}

export function useSidebarHandlers(params: UseSidebarHandlersParams): SidebarHandlers {
  const { state, onUpdateProject, onOpenSession, isMobile, onMobileClose } = params
  const {
    setContextMenu,
    editingProject,
    setEditingProject,
    editInputRef,
    editingCategory,
    setEditingCategory,
    categoryEditInputRef,
    addCategory,
    updateCategory,
    categories,
    setIsResizing,
    moveProjectToCategory,
  } = state

  // Project handlers
  const handleSelectExecutable = useCallback(
    async (project: Project) => {
      const executable = await electronAPI?.selectExecutable?.()
      if (executable) onUpdateProject(project.path, { executable })
      setContextMenu(null)
    },
    [onUpdateProject, setContextMenu]
  )

  const handleClearExecutable = useCallback(
    (project: Project) => {
      onUpdateProject(project.path, { executable: undefined })
      setContextMenu(null)
    },
    [onUpdateProject, setContextMenu]
  )

  const handleRunExecutable = useCallback(
    async (project: Project) => {
      if (project.executable) {
        const result = await electronAPI?.runExecutable?.(project.executable, project.path)
        if (result && !result.success) console.error('Failed to run executable:', result.error)
      }
      setContextMenu(null)
    },
    [setContextMenu]
  )

  // Rename handlers
  // Ref tracks cancel intent so blur handler can skip saving after Escape
  const renameCancelledRef = useRef(false)

  const handleStartRename = useCallback(
    (e: React.MouseEvent, project: Project) => {
      e.stopPropagation()
      renameCancelledRef.current = false
      setEditingProject({ path: project.path, name: project.name })
      setTimeout(() => editInputRef.current?.select(), 0)
    },
    [setEditingProject, editInputRef]
  )

  const handleRenameSubmit = useCallback(() => {
    if (renameCancelledRef.current) {
      renameCancelledRef.current = false
      return
    }
    if (editingProject && editingProject.name.trim()) {
      onUpdateProject(editingProject.path, { name: editingProject.name.trim() })
    }
    setEditingProject(null)
  }, [editingProject, onUpdateProject, setEditingProject])

  const handleRenameKeyDown = useCallback(
    (e: React.KeyboardEvent) => {
      if (e.key === 'Enter') handleRenameSubmit()
      else if (e.key === 'Escape') {
        renameCancelledRef.current = true
        setEditingProject(null)
      }
    },
    [handleRenameSubmit, setEditingProject]
  )

  // Category handlers
  const handleAddCategory = useCallback(() => {
    const newId = addCategory('New Category')
    setEditingCategory({ id: newId, name: 'New Category' })
    setTimeout(() => categoryEditInputRef.current?.select(), 0)
  }, [addCategory, setEditingCategory, categoryEditInputRef])

  const handleOpenCategoryAsProject = useCallback(
    async (categoryName: string) => {
      const metaPath = await electronAPI?.getCategoryMetaPath?.(categoryName)
      if (metaPath) onOpenSession(metaPath)
    },
    [onOpenSession]
  )

  const handleOpenAllProjects = useCallback(async () => {
    const metaPath = await electronAPI?.getMetaProjectsPath?.()
    if (metaPath) onOpenSession(metaPath)
  }, [onOpenSession])

  // Category rename cancel ref (same pattern as project rename)
  const categoryRenameCancelledRef = useRef(false)

  const handleStartCategoryRename = useCallback(
    (category: ReturnType<typeof useWorkspaceStore.getState>['categories'][0]) => {
      categoryRenameCancelledRef.current = false
      setEditingCategory({ id: category.id, name: category.name })
      setTimeout(() => categoryEditInputRef.current?.select(), 0)
    },
    [setEditingCategory, categoryEditInputRef]
  )

  const handleCategoryRenameSubmit = useCallback(() => {
    if (categoryRenameCancelledRef.current) {
      categoryRenameCancelledRef.current = false
      return
    }
    if (editingCategory && editingCategory.name.trim()) {
      updateCategory(editingCategory.id, { name: editingCategory.name.trim() })
    }
    setEditingCategory(null)
  }, [editingCategory, updateCategory, setEditingCategory])

  const handleCategoryRenameKeyDown = useCallback(
    (e: React.KeyboardEvent) => {
      if (e.key === 'Enter') handleCategoryRenameSubmit()
      else if (e.key === 'Escape') {
        categoryRenameCancelledRef.current = true
        setEditingCategory(null)
      }
    },
    [handleCategoryRenameSubmit, setEditingCategory]
  )

  const toggleCategoryCollapse = useCallback(
    (categoryId: string) => {
      const category = categories.find((c) => c.id === categoryId)
      if (category) updateCategory(categoryId, { collapsed: !category.collapsed })
    },
    [categories, updateCategory]
  )

  // Resize handler
  const handleMouseDown = useCallback(
    (e: React.MouseEvent) => {
      e.preventDefault()
      setIsResizing(true)
    },
    [setIsResizing]
  )

  // Backdrop handler
  const handleBackdropClick = useCallback(() => {
    if (isMobile && onMobileClose) {
      onMobileClose()
    }
  }, [isMobile, onMobileClose])

  return {
    handleSelectExecutable,
    handleClearExecutable,
    handleRunExecutable,
    handleStartRename,
    handleRenameSubmit,
    handleRenameKeyDown,
    handleAddCategory,
    handleOpenCategoryAsProject,
    handleOpenAllProjects,
    handleStartCategoryRename,
    handleCategoryRenameSubmit,
    handleCategoryRenameKeyDown,
    toggleCategoryCollapse,
    handleMouseDown,
    handleBackdropClick,
  }
}

// Helper for creating category with project
export function useCreateCategoryWithProject(
  state: SidebarState
): (projectPath: string) => void {
  const { addCategory, moveProjectToCategory, setContextMenu, setEditingCategory, categoryEditInputRef } = state

  return useCallback(
    (projectPath: string) => {
      const newId = addCategory('New Category')
      moveProjectToCategory(projectPath, newId)
      setContextMenu(null)
      setEditingCategory({ id: newId, name: 'New Category' })
      setTimeout(() => categoryEditInputRef.current?.select(), 0)
    },
    [addCategory, moveProjectToCategory, setContextMenu, setEditingCategory, categoryEditInputRef]
  )
}

import { useCallback, useRef, useState } from 'react'
import type { Api } from '../api'
import type { BackendId } from '../api/types'
import type { AppSettings } from './useSettings'
import { OpenTab, Project } from '../stores/workspace'
import { TileLayout, DropZone, splitTile, addTileToLayout, addTabToExistingTile } from '../components/TiledTerminalView'
import { clearTerminalBuffer } from '../components/terminal/Terminal'

interface UseProjectHandlersOptions {
  api: Api
  projects: Project[]
  openTabs: OpenTab[]
  settings: AppSettings | null
  tileLayout: TileLayout[]
  addProject: (project: { path: string; name: string }) => void
  removeTab: (id: string) => void
  addTab: (tab: OpenTab) => void
  setActiveTab: (id: string) => void
  setTileLayout: (layout: TileLayout[]) => void
}

interface ClosedTabInfo {
  projectPath: string
  sessionId?: string
  title: string
  backend?: string
}

interface UseProjectHandlersReturn {
  handleAddProject: () => Promise<void>
  handleAddProjectsFromParent: () => Promise<void>
  handleOpenSession: (projectPath: string, sessionId?: string, slug?: string, initialPrompt?: string, forceNewSession?: boolean) => Promise<void>
  handleOpenSessionAtPosition: (projectPath: string, dropZone: DropZone | null, containerSize: { width: number; height: number }, currentLayout?: TileLayout[]) => Promise<void>
  handleCloseTab: (tabId: string) => void
  handleCloseProjectTabs: (projectPath: string) => void
  handleProjectCreated: (projectPath: string, projectName: string) => void
  handleUndoCloseTab: () => void
  canUndoCloseTab: boolean
}

export function useProjectHandlers({
  api,
  projects,
  openTabs,
  settings,
  tileLayout,
  addProject,
  removeTab,
  addTab,
  setActiveTab,
  setTileLayout
}: UseProjectHandlersOptions): UseProjectHandlersReturn {
  const closedTabsRef = useRef<ClosedTabInfo[]>([])
  const [closedTabCount, setClosedTabCount] = useState(0)

  // Keep a ref to the latest tileLayout so async callbacks always read the freshest state
  const tileLayoutRef = useRef(tileLayout)
  tileLayoutRef.current = tileLayout

  const handleAddProject = useCallback(async () => {
    const path = await api.addProject()
    if (path) {
      const name = path.split(/[/\\]/).pop() || path
      addProject({ path, name })
      await api.ttsInstallInstructions?.(path)
    }
  }, [api, addProject])

  const handleAddProjectsFromParent = useCallback(async () => {
    const projectsToAdd = await api.addProjectsFromParent?.()
    if (projectsToAdd && projectsToAdd.length > 0) {
      const existingPaths = new Set(projects.map((p) => p.path))
      const newProjects = projectsToAdd.filter((p) => !existingPaths.has(p.path))

      for (const project of newProjects) {
        addProject({ path: project.path, name: project.name })
        await api.ttsInstallInstructions?.(project.path)
      }
    }
  }, [api, addProject, projects])

  const handleOpenSession = useCallback(async (projectPath: string, sessionId?: string, slug?: string, initialPrompt?: string, forceNewSession?: boolean) => {
    // Check if this session is already open
    if (sessionId) {
      const existingTab = openTabs.find(tab => tab.sessionId === sessionId)
      if (existingTab) {
        setActiveTab(existingTab.id)
        return
      }
    }

    // Get project and determine effective backend
    const project = projects.find((p) => p.path === projectPath)
    const effectiveBackend = (project?.backend && project.backend !== 'default'
      ? project.backend
      : (settings?.backend && settings.backend !== 'default'
        ? settings.backend
        : 'claude')) as BackendId

    // Only discover sessions if no specific sessionId was requested
    if (!forceNewSession && !sessionId) {
      try {
        const sessions = await api.discoverSessions(projectPath, effectiveBackend)
        if (sessions.length > 0) {
          const [mostRecent] = sessions
          const existingTab = openTabs.find((tab) => tab.sessionId === mostRecent.sessionId)

          if (existingTab) {
            setActiveTab(existingTab.id)
            return
          }
          sessionId = mostRecent.sessionId
          slug = mostRecent.slug
        }
      } catch (e) {
        console.error('Failed to discover sessions for project:', e)
      }
    }

    const projectName = projectPath.split(/[/\\]/).pop() || projectPath
    const title = slug ? `${projectName} - ${slug}` : `${projectName} - New`

    try {
      await api.ttsInstallInstructions?.(projectPath)

      const ptyId = await api.spawnPty(projectPath, sessionId, undefined, effectiveBackend)

      // Compute tile layout BEFORE adding tab so both update together,
      // preventing useEffectiveLayout from auto-adding at the wrong position
      const currentLayout = tileLayoutRef.current
      const newLayout = addTileToLayout(currentLayout, ptyId, null, window.innerWidth, window.innerHeight)

      addTab({
        id: ptyId,
        projectPath,
        sessionId,
        title,
        ptyId,
        backend: effectiveBackend
      })
      setTileLayout(newLayout)

      // If an initial prompt was provided, send it after a short delay
      if (initialPrompt) {
        setTimeout(() => {
          api.writePty(ptyId, initialPrompt)
          setTimeout(() => {
            api.writePty(ptyId, '\r')
          }, 100)
        }, 1500)
      }
    } catch (e: any) {
      console.error('Failed to spawn PTY:', e)
      const errorMsg = e?.message || String(e)
      alert(`Failed to start Claude session:\n\n${errorMsg}\n\nPlease ensure Claude Code is installed and try restarting the application.`)
    }
  }, [api, addTab, openTabs, projects, setActiveTab, settings?.backend, setTileLayout])

  const handleOpenSessionAtPosition = useCallback(async (projectPath: string, dropZone: DropZone | null, containerSize: { width: number; height: number }, currentLayout?: TileLayout[]) => {
    // Use the effective layout passed from the drop handler (matches what computeDropZone used),
    // falling back to the latest stored layout via ref (not the stale closure value)
    const layoutToUse = currentLayout || tileLayoutRef.current
    console.log('[App] handleOpenSessionAtPosition called with:', { projectPath, dropZone, containerSize, currentTileLayout: layoutToUse, hadCurrentLayout: !!currentLayout })

    if (!projectPath || projectPath === 'pending') {
      console.error('[App] Invalid project path:', projectPath)
      return
    }

    const project = projects.find((p) => p.path === projectPath)
    console.log('[App] Found project:', project)
    const effectiveBackend = (project?.backend && project.backend !== 'default'
      ? project.backend
      : (settings?.backend && settings.backend !== 'default'
        ? settings.backend
        : 'claude')) as BackendId
    console.log('[App] Using backend:', effectiveBackend)

    // Always create a new session when dragging to a position
    const sessionId: string | undefined = undefined
    const slug: string | undefined = undefined

    const projectName = projectPath.split(/[/\\]/).pop() || projectPath
    const title = slug ? `${projectName} - ${slug}` : `${projectName} - New`

    try {
      await api.ttsInstallInstructions?.(projectPath)
      const ptyId = await api.spawnPty(projectPath, sessionId, undefined, effectiveBackend)

      // Calculate the new layout based on the drop zone
      let newLayout: TileLayout[]

      // Re-read the latest layout after the async spawn (layout may have changed during await)
      const latestLayout = currentLayout || tileLayoutRef.current

      // Sidebar drag onto swap zone → always tab into target tile
      if (dropZone && dropZone.type === 'swap') {
        const targetTile = latestLayout.find(t => t.id === dropZone.targetTileId)
        if (targetTile) {
          console.log('[App] Adding as sub-tab to existing tile')
          newLayout = addTabToExistingTile(latestLayout, targetTile.id, ptyId)
        } else {
          console.log('[App] Using addTileToLayout for swap (target not found)')
          newLayout = addTileToLayout(latestLayout, ptyId, dropZone.targetTileId, containerSize.width, containerSize.height)
        }
      } else if (dropZone && dropZone.type !== 'swap') {
        const direction = dropZone.type.replace('split-', '') as 'top' | 'bottom' | 'left' | 'right'
        console.log('[App] Using splitTile with direction:', direction, 'targetTileId:', dropZone.targetTileId)
        newLayout = splitTile(latestLayout, dropZone.targetTileId, ptyId, direction)
      } else {
        console.log('[App] Using addTileToLayout with no drop zone (null)')
        newLayout = addTileToLayout(latestLayout, ptyId, null, containerSize.width, containerSize.height)
      }
      console.log('[App] New layout calculated:', newLayout)

      // Add tab FIRST, then set layout LAST.
      // This ensures our positioned layout is the final state update and
      // won't be overwritten by useEffectiveLayout's generic positioning
      // if there's an intermediate render between these two updates.
      addTab({
        id: ptyId,
        projectPath,
        sessionId,
        title,
        ptyId,
        backend: effectiveBackend
      })
      setTileLayout(newLayout)
    } catch (e: any) {
      console.error('Failed to spawn PTY:', e)
      const errorMsg = e?.message || String(e)
      alert(`Failed to start Claude session:\n\n${errorMsg}\n\nPlease ensure Claude Code is installed and try restarting the application.`)
    }
  }, [api, addTab, projects, openTabs, settings?.backend, setTileLayout])

  const handleCloseTab = useCallback((tabId: string) => {
    const tab = openTabs.find(t => t.id === tabId)
    if (tab) {
      closedTabsRef.current.push({
        projectPath: tab.projectPath,
        sessionId: tab.sessionId,
        title: tab.title,
        backend: tab.backend
      })
      setClosedTabCount(closedTabsRef.current.length)
    }
    api.killPty(tabId)
    clearTerminalBuffer(tabId)
    removeTab(tabId)
  }, [api, openTabs, removeTab])

  const handleCloseProjectTabs = useCallback((projectPath: string) => {
    const tabsToClose = openTabs.filter(tab => tab.projectPath === projectPath)
    tabsToClose.forEach(tab => {
      closedTabsRef.current.push({
        projectPath: tab.projectPath,
        sessionId: tab.sessionId,
        title: tab.title,
        backend: tab.backend
      })
      api.killPty(tab.id)
      clearTerminalBuffer(tab.id)
      removeTab(tab.id)
    })
    setClosedTabCount(closedTabsRef.current.length)
  }, [api, openTabs, removeTab])

  const handleProjectCreated = useCallback((projectPath: string, projectName: string) => {
    addProject({ path: projectPath, name: projectName })
    handleOpenSession(projectPath, undefined, undefined, undefined, false)
  }, [addProject, handleOpenSession])

  const handleUndoCloseTab = useCallback(() => {
    const info = closedTabsRef.current.pop()
    if (!info) return
    setClosedTabCount(closedTabsRef.current.length)
    handleOpenSession(info.projectPath, info.sessionId)
  }, [handleOpenSession])

  return {
    handleAddProject,
    handleAddProjectsFromParent,
    handleOpenSession,
    handleOpenSessionAtPosition,
    handleCloseTab,
    handleCloseProjectTabs,
    handleProjectCreated,
    handleUndoCloseTab,
    canUndoCloseTab: closedTabCount > 0
  }
}

