    volume,
    setVolume,
    speed,
    setSpeed,
    skipOnNew,
    setSkipOnNew,
    voiceOutputEnabled,

    // State
    sortedCategories,
    projectsByCategory,
    expandedProject,
    sessions,
    dropTarget,
    draggedCategory,
    draggedProject,
    editingCategory,
    categoryEditInputRef,
    contextMenu,
    setContextMenu,
    categoryContextMenu,
    setCategoryContextMenu,
